  setOpenOtpVerification: (open: boolean) => void;
  otp: string[];
  setOtp: (otp: string[]) => void;
  email?: string;
  timeLeft: number;
  canResend: boolean;
  handleRequestforOtp: (e: React.FormEvent) => void;
  formSubmit: () => void;
  setTimeLeft: (time: number) => void;
}

const OtpInputModal: React.FC<OtpInputModalProps> = ({
  setOpenOtpVerification,
  otp,
  setOtp,
  email,
  timeLeft,
  canResend,
  handleRequestforOtp,
  formSubmit,
  setTimeLeft,
}) => {
  const [otpError, setOtpError] = useState<string>('');

  useEffect(() => {
    const firstInput = document.getElementById('otp-0');
    firstInput?.focus();
  }, []);

  const formatTime = (time: number) => {
    if (time) {
      const minutes = Math.floor(time / 60000);
      const seconds = Math.floor((time % 60000) / 1000);
      return `${minutes < 10 ? '0' : ''}${minutes}:${
        seconds < 10 ? '0' : ''
      }${seconds}`;
    } else {
      return '00:00';
    }
  };

  const handleOtpSubmit = () => {
    const enterOtp = otp.join('');
    if (Boolean(enterOtp) && enterOtp?.length === 6) {
      toast.dismiss();
      setTimeLeft(0);
      setOpenOtpVerification(false);
      setTimeout(() => {
        formSubmit();
      }, 1000);
    } else {
      setOtpError('Please enter otp');
    }
  };

  return (
